export type SpellType = "sorcery" | "incantation";

export type Spell = {
  id: string;
  name: string;
  type: SpellType;
  // Wiki "Group" column — the spell school catalysts boost (Erdtree, Bestial,
  // Dragon Cult, Golden Order, Frenzied Flame, Black Flame, Giants' Flame,
  // Dragon Communion, Two Fingers, Spiral Tower, Messmer's Flame, Blood Oath,
  // Servants of Rot, Miquellan for incantations; Glintstone, Carian Sword,
  // Full Moon, etc. for sorceries).
  category: string;
  // Wiki "Bonus" column — gameplay role: Damage / Healing / Buff / Utility.
  // Drives display chips and could be used by future recommendation filters.
  bonus?: "Damage" | "Healing" | "Buff" | "Utility";
  requirements: { intelligence?: number; faith?: number; arcane?: number };
  fpCost: number;
  slots: number;
  effect: string;
  image?: string;
  dlc?: boolean;
  // Catalyst ids whose effect notably boosts this spell. When any catalyst
  // in the loadout has an id contained in this array, the SpellRecommendations
  // panel highlights the card (gold border + "Boosted by this catalyst" chip).
  // Omit the property if no catalyst gives a notable boost.
  boosted_by_catalyst?: string[];
};

